"""
Hardcoded fundamental profiles for ~178 major ASX-listed companies.
Data as at April 2026 (research knowledge + source CSV).

Schema per record:
    mc    : market cap (A$B)
    sh    : shares outstanding (B)
    px    : share price (A$)
    dy    : dividend yield (%)
    frank : franking level (%)
    pe    : trailing P/E ratio
    pb    : price / book
    beta  : 12-month beta vs ASX 200
    roe   : return on equity (%)
    de    : debt / equity ratio
    rev   : revenue, latest annual (A$B)
    np    : net profit / loss, latest annual (A$B)
    desc  : one-line business description
    state : HQ state / territory (or country code if foreign)
    ops   : primary country / region of operations
    dual  : dual listed (bool)
    dex   : secondary exchange(s)
    ceo   : CEO / MD name
    web   : investor relations website (no https://)
    yr    : year founded / established
    fye   : fiscal year end month abbreviation
    curr  : reporting currency
    cat   : market cap category
"""

from typing import TypedDict


class CompanyRecord(TypedDict, total=False):
    mc: float
    sh: float
    px: float
    dy: float
    frank: int
    pe: float
    pb: float
    beta: float
    roe: float
    de: float
    rev: float
    np: float
    desc: str
    state: str
    ops: str
    dual: bool
    dex: str
    ceo: str
    web: str
    yr: int
    fye: str
    curr: str
    cat: str


